<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header ui-draggable-handle d-flex">
                        <h5 class="modal-title">{{ $t('Notes') }}</h5>
                        <button type="button" class="close" v-on:click="Close">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>
                        <span class="user-guide">
                            <a class="ancuserguide text-white" data-toggle="collapse" href="#collapseReplyUG" role="button"
                                aria-expanded="false" aria-controls="collapseExample"> <em
                                class="fa fa-files-o pr-2"></em> {{ $t('GuideForUser') }}</a>
                            <div id="collapseReplyUG" class="divancuserguide collapse overflow-auto">
                                <div id="scrollbarreplyuserguideMangeView" class="custom-scrollbar-js">
                                    <div class="con" v-html="$t('UgAddNotes')"></div>
                                </div>
                            </div>
                        </span>
                    </div>

                    <div class="modal-body">
                        <dynamic-form lang="en" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="UploadFileWithNote">
                            <template v-slot:tgslot-Description="{ data }">
                                <ckeditor :editor="editor" v-model="noteDescription"
                                    :class="{ 'is-invalid': data.error != '' }">
                                </ckeditor>
                                <span class="invalid-feedback">{{ data.error }}</span>
                                <!-- <ckeditor :editor="editor" @ready="onReady" @input="updateCkeditorModel($event, data)"></ckeditor>
                                <span name="Description" class="invalid-feedback d-block">{{ data.error }}</span>
                                <input type="hidden" v-model="data.fieldInfo.value"/>  -->
                            </template>
                        </dynamic-form>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import DataServices from "@/services/DataService";
export default {
    props: {
        configdata: {
            type: Array,
            required: true
        },
        id: {
            type: Number,
            required: false
        },
        modulename: {
            type: String,
            required: true
        },
        submodulecode: {
            type: String,
            required: true
        },
        callbackfunction: {
            type: Function
        },
        viewMode: {
            type: String,
            required: true
        },
        NoteData: {
            type: String,
            required: false
        }
    },
    data() {
        return {
            editor: this.CLASSIC_EDITOR,
            content: '',
            ticketType: '',
            noteDescription: '',
            isLoading: false,
            TicketBindList: [],
            Description: null,
            FileName: null,
            checkFileValidSize: false,
            checkFileValidExt: false,
            allowedPerFileSizeInMb: 0,
            disallowFileTypes: '',
            file: null,
            noteData: [],
            noteId: 0,
            ticketId: 0,
            TicketNoteId: 0,
            note: '',
            fileData: [],
            ticketModel: {
                NoteDescription: '',
                transferType: '',
                TicketId: 0,
                ModuleName: '',
                SubModuleCode: '',
                NoteId: 0,
                WorkOrderId: 0,
                fileData: []
            },
            FormSchema: [
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "SlotField",
                            label: this.$t('Note Description'),
                            name: "Description",
                            value: "",
                            placeholder: "",
                            config: {
                                options: [],

                            },
                            settings: {
                                isInSlot: true
                            },
                            visibility: true,
                            validationRules: { "required": true, max: 5000 },
                        },
                    ]
                },
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "RadioField",
                            label: "",
                            name: "QuickViewType",
                            value: 2,
                            placeholder: "",
                            validationRules: { "required": false, max: 200 },
                            config: {
                                options: [{ name: 'Private', value: 1 }, { name: 'Public', value: 2 }],
                                showAddIcon: false,
                                onChange: this.onChangeRadio
                            },

                        }
                    ],
                },
                {
                    group_name: "Attachment",
                    layoutType: "single",
                    Data: [
                        {
                            astype: "FileField",
                            showLabel: false,
                            name: "NoteAttachment",
                            placeholder: "",
                            validationRules: "",
                            FieldIndex: 0,
                            config: {
                                maxSize: 5,  
                                options: [],                              
                                showSelectedFiles: [],
                                onDeleteSelectedFiles: this.onDeleteSelectedFiles,
                                onChange: this.GetBase64String,
                                onClickSelectedFiles: this.onClickSelectedFiles,
                                showAddIcon: false,
                                onAddButtonClick: '',
                                multiple: true
                            },
                        }
                    ]
                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success save",
                    text: "<i class='fa fa-save pr-2'></i>Submit"
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.Close
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        this.configData();
        if (vm.$parent.noteId > 0) {
            vm.TicketNoteId = vm.$parent.noteId;
            vm.ticketId = vm.$parent.ticketId;
            vm.noteDescription = vm.$parent.note;
            vm.FormSchema[1].Data[0].value = vm.$parent.privacy === 'Private' ? 1 : 2;

            const attachmentData = vm.NoteData;
            attachmentData.forEach(element => {
                if (element.NOTE_ID === vm.$parent.noteId && element.ATTACHMENTS_JSON) {
                    var parsedAttachments = [];
                    parsedAttachments = JSON.parse(element.ATTACHMENTS_JSON);                  
                    parsedAttachments.forEach(itm => {
                        const attachmentItem = {
                            attachmentName: itm.ATTACHMENT_NAME,
                            attachmentPath: itm.ATTACHMENT_PATH, 
                        };
                        vm.FormSchema[2].Data[0].config.showSelectedFiles.push(attachmentItem);
                    });
                }
            });
        }
    },
    methods: {
        onReady(editor) {
            editor.ui.getEditableElement().parentElement.insertBefore(
                editor.ui.view.toolbar.element,
                editor.ui.getEditableElement()
            );
        },
        SizeToMb: function (bytes) {
            var vueObj = this;
            var sizeInBuytes = parseInt(vueObj.allowedPerFileSizeInMb, 10) * 1048576;
            if (bytes > sizeInBuytes) {
                return -1;
            }
            else {
                var byesInMB = (bytes / 1024) / 1024;
                return byesInMB;
            }
        },
        configData: function (value) {
            var vm = this;
            var data = vm.configdata;
            $.each(data, $.proxy(function (index1, item) {
                if (item.CORE_CONFIG_KEY == "TicketFileSize") {
                    this.allowedPerFileSizeInMb = item.CONFIG_DATA_VALUE;
                }
                else if (item.CORE_CONFIG_KEY == "TicketDisallowedFileTypes") {
                    this.disallowFileTypes = item.CONFIG_DATA_VALUE;
                    this.fileTypeList = this.AttachmentDisallowedFileType(this.disallowFileTypes);
                    vm.FormSchema[2].Data[0].config.reject = this.fileTypeList;
                }
            }, this));
        },
        onClickSelectedFiles: function(item){
            var vm = this;
            vm.isLoading = true;
            var param = `filePath=${item.attachmentPath}&fileName=${item.attachmentName}`;
            DataServices.DownloadFile(param).then(function (response) {
                const byteData = response.data;
                const fileURL = `data:image/png;base64;base64,${byteData}`;
                var fileLink = document.createElement('a');
                fileLink.href = fileURL;
                fileLink.setAttribute('download', item.attachmentName);
                document.body.appendChild(fileLink);
                fileLink.click();
                vm.isLoading = false;
            });
        },
        setFile: function (e) {
            var vm = this;
            vm.file = e.target.files[0];
            vm.FileName = e.target.files[0].name;
        },
        onDeleteSelectedFiles: function (index, item) {
            this.FormSchema[2].Data[0].config.showSelectedFiles.splice(index, 1);
        },
        onChangeRadio: function (e, field) {
            var vm = this;
            vm.ticketType = e.target.dataset.value;
        },
        GetBase64String: function (evt, field) {
            try {
                var vm = this;
                const files = evt.target.files || field.value; 
                //const files = evt.target.files;

                if (!vm.fileData) {
                    vm.fileData = [];
                }

                for (let i = 0; i < files.length; i++) {
                    const file = files[i];

                    const alreadyExists = vm.fileData.some(f => f.fileName === file.name && f.fileSize === file.size);
                    if (alreadyExists) continue;

                    const reader = new FileReader();

                    reader.onload = (function (theFile) {
                        return function (e) {
                            var binaryData = e.target.result;
                            var base64StringEncoded = window.btoa(binaryData);

                            var fileName = theFile.name;
                            var n = fileName.lastIndexOf(".");
                            var extensionName = fileName.substring(n + 1);

                            var attachemnetMime = JSON.stringify({
                                ContentType: theFile.type,
                                Size: theFile.size,
                                Extension: extensionName
                            });

                            var fileObj = {
                                attachement_mime: attachemnetMime,
                                fileName: theFile.name,
                                base64String: base64StringEncoded,
                                fileSize: theFile.size,
                                contentType: theFile.type
                            };
                            vm.fileData.push(fileObj);
                        };
                    })(file);

                    reader.readAsBinaryString(file);
                }
                evt.target.value = '';
            } catch (ex) {
                console.error(ex);
            }
        },
        UploadFileWithNote: function (formfields, val) {
            var vm = this;
            vm.isLoading = true;
            vm.buttons[0].class += " disabled";
            if (vm.noteDescription == '' || vm.noteDescription == null) {
                this.showError = true;
                vm.isLoading = false;
            }
            else {
                var extArray = vm.disallowFileTypes.split(',');
                if (extArray.includes(vm.fileExt)) {
                    vm.checkFileValidExt = false;
                    vm.ShowAlert(vm.$t("InvalidFileUploadMsg", [vm.fileName, vm.disallowFileTypes]), "warning", true, vm.$t("Alert"));
                    vm.buttons[0].class = "btn btn-success";
                    vm.isLoading = false;
                }
                else {
                    vm.checkFileValidExt = true;
                }

                var fileSizeInMB = this.SizeToMb(vm.fileSize);

                if (fileSizeInMB > parseInt(vm.allowedPerFileSizeInMb, 10)) {
                    vm.checkFileValidSize = false;
                    vm.ShowAlert(vm.$t("ExceedAllowedSize", [vm.fileName, vm.allowedPerFileSizeInMb]), "warning", true, vm.$t("Alert"));
                    vm.buttons[0].class = "btn btn-success";
                    vm.isLoading = false;
                }
                else {
                    vm.checkFileValidSize = true;
                }

                if (fileSizeInMB < 0) {
                    vm.checkFileValidSize = false;
                    vm.ShowAlert(vm.$t("ExceedAllowedSize", [vm.fileName, vm.allowedPerFileSizeInMb]), "warning", true, vm.$t("Alert"));
                    vm.buttons[0].class = "btn btn-success";
                    vm.isLoading = false;

                } else {
                    vm.checkFileValidSize = true;
                }

                if (vm.checkFileValidExt == true && vm.checkFileValidSize == true) {
                    vm.ticketModel.transferType = vm.ticketType == 1 ? 'Private' : 'Public';
                    vm.ticketModel.NoteDescription = vm.noteDescription;
                    vm.ticketModel.TicketId = vm.id == 0 || vm.id == null ? vm.TicketNoteId : vm.id;
                    vm.ticketModel.NoteId = vm.TicketNoteId;
                    vm.ticketModel.ModuleName = vm.modulename;
                    vm.ticketModel.SubModuleCode = vm.submodulecode;
                    vm.ticketModel.fileData = vm.fileData;
                    var formData = JSON.stringify(vm.ticketModel);
                    DataServices.AddNote(formData).then((response) => {
                        try {
                            vm.isLoading = false;
                            if (response.data != null && response.data != "" && response.data.status == "Success") {
                                vm.ShowAlert(vm.$t("AddedSuccess", [vm.$t("Notes")]), "success", true, vm.$t("Alert"));
                                $("input[type=text]").val('');
                                vm.$emit("LoadNoteForQuickView");
                                vm.Close();
                                vm.callbackfunction();
                            }
                            else {
                                vm.ShowAlert(vm.$t("InvalidFileTypMsg"), "failure", true, vm.$t("Alert"));
                                vm.buttons[0].class = "btn btn-success";
                                vm.FileSrc = '';
                                $("input[type=text]").val('');
                            }
                        } catch (exinner) {
                            return HandleErrorOccured(exinner, 'saveNote');
                        }
                    });
                }
            }
        },
        Close: function () {
            var vueObj = this;
            vueObj.noteDescription = null;
            vueObj.FileName = null;
            vueObj.file = null;
            vueObj.FormSchema[2].Data[0].config.onChange = vueObj.GetBase64String;
            this.$emit("Close");
            vueObj.$parent.isShowAddNote = false;
            vueObj.$parent.noteId = 0;
            if (vueObj.viewMode == 'Notes') {
                document.getElementById('tab-notes').click();
            }
            else {
                vueObj.$parent.LoadNotesForQuickView();
            }
            vueObj.$parent.noRecord = false;
        }
    }
}
</script>
<style>
.my-popups .modal-body .user-guide {
    position: absolute;
    right: 23px !important;
    top: 15px !important;
    background-color: transparent !important;
}
</style>